"use client";

import { createContext, createElement, useContext } from "react";
import type { ComponentProps, ImgHTMLAttributes } from "react";

import { Button } from "@/components/ui/button";
import { cn } from "@/lib/utils";

import type { Post } from "./types";

export type { Post } from "./types";

const BlockImage = (props: ImgHTMLAttributes<HTMLImageElement>) =>
  createElement("img", props);

interface PostCardContextValue {
  onReadMore?: (post: Post) => void;
  post: Post;
  showAuthor: boolean;
  showCategory: boolean;
  showImage: boolean;
  variant: "compact" | "covered" | "default" | "horizontal";
}

const PostCardContext = createContext<PostCardContextValue | null>(null);

export const usePostCard = () => {
  const context = useContext(PostCardContext);
  if (!context) {
    throw new Error("PostCard components must be used within PostCard");
  }
  return context;
};

const DEFAULT_POST: Post = {
  author: {
    avatar: "https://picsum.photos/seed/sarah/150/150",
    name: "Sarah Chen",
  },
  category: "Tutorial",
  coverImage: "https://picsum.photos/seed/post-card/800/450",
  excerpt:
    "Learn how to build conversational interfaces with our comprehensive component library designed for AI-powered applications.",
  publishedAt: "2024-01-15",
  readTime: "5 min read",
  tags: ["Tutorial", "Components"],
  title: "Getting Started with Agentic UI Components",
};

const formatDate = (date: string) =>
  new Date(date).toLocaleDateString("en-US", {
    day: "numeric",
    month: "short",
    year: "numeric",
  });

export interface PostCardProps extends ComponentProps<"article"> {
  actions?: {
    onReadMore?: (post: Post) => void;
  };
  appearance?: {
    showAuthor?: boolean;
    showCategory?: boolean;
    showImage?: boolean;
    variant?: "default" | "compact" | "horizontal" | "covered";
  };
  data?: {
    post?: Post;
  };
}

export const PostCardImage = ({
  className,
  ...props
}: ComponentProps<"div">) => {
  const { post, showImage } = usePostCard();
  if (!showImage) {
    return null;
  }
  return (
    <div className={cn("overflow-hidden bg-muted", className)} {...props}>
      {post.coverImage ? (
        <BlockImage
          alt={post.title ?? ""}
          className="size-full object-cover"
          src={post.coverImage}
        />
      ) : (
        <div className="size-full bg-muted" />
      )}
    </div>
  );
};

export const PostCardCategory = ({
  children,
  className,
  ...props
}: ComponentProps<"p">) => {
  const { post, showCategory } = usePostCard();
  if (!(showCategory && (children || post.category))) {
    return null;
  }
  return (
    <p
      className={cn(
        "font-medium text-[10px] text-muted-foreground uppercase tracking-wide",
        className
      )}
      {...props}
    >
      {children ?? post.category}
    </p>
  );
};

export const PostCardTags = ({
  children,
  className,
  ...props
}: ComponentProps<"div">) => {
  const { post } = usePostCard();
  const tags = post.tags?.slice(0, 2) ?? [];
  if (!(children || tags.length > 0)) {
    return null;
  }
  return (
    <div className={cn("flex flex-wrap gap-1", className)} {...props}>
      {children ??
        tags.map((tag) => (
          <span
            className="rounded-full bg-muted px-2 py-0.5 text-muted-foreground text-xs"
            key={tag}
          >
            {tag}
          </span>
        ))}
    </div>
  );
};

export const PostCardAuthor = ({
  children,
  className,
  ...props
}: ComponentProps<"div">) => {
  const { post, showAuthor } = usePostCard();
  if (!showAuthor) {
    return null;
  }
  return (
    <div className={cn("flex items-center gap-2", className)} {...props}>
      {children ?? (
        <>
          {post.author?.avatar && (
            <BlockImage
              alt={post.author.name ?? ""}
              className="size-6 rounded-full object-cover"
              src={post.author.avatar}
            />
          )}
          <div className="text-xs">
            {post.author?.name && (
              <p className="font-medium">{post.author.name}</p>
            )}
            {post.publishedAt && (
              <p className="text-muted-foreground">
                {formatDate(post.publishedAt)}
              </p>
            )}
          </div>
        </>
      )}
    </div>
  );
};

export const PostCardAction = ({
  children,
  ...props
}: ComponentProps<typeof Button>) => {
  const { onReadMore, post } = usePostCard();
  return (
    <Button onClick={() => onReadMore?.(post)} size="sm" {...props}>
      {children ?? "Read"}
    </Button>
  );
};

export const PostCardText = ({
  children,
  className,
  ...props
}: ComponentProps<"div">) => {
  const { post } = usePostCard();
  return (
    <div className={className} {...props}>
      {children ?? (
        <>
          <PostCardCategory />
          {post.title && (
            <h3 className="line-clamp-2 font-medium text-sm leading-tight">
              {post.title}
            </h3>
          )}
          {post.excerpt && (
            <p className="mt-1 line-clamp-2 text-muted-foreground text-xs">
              {post.excerpt}
            </p>
          )}
          <PostCardTags className="mt-1.5" />
        </>
      )}
    </div>
  );
};

const CoveredPostCard = () => {
  const { post } = usePostCard();
  return (
    <div className="relative overflow-hidden rounded-lg border">
      <PostCardImage className="min-h-[280px] w-full sm:aspect-[16/9] sm:min-h-0" />
      <div className="absolute inset-0 bg-black/60" />
      <div className="absolute inset-0 flex flex-col justify-end p-4 text-white">
        <PostCardCategory className="text-white/70" />
        {post.title && (
          <h2 className="mt-1 font-semibold text-lg leading-tight">
            {post.title}
          </h2>
        )}
        {post.excerpt && (
          <p className="mt-1 line-clamp-2 text-sm text-white/80">
            {post.excerpt}
          </p>
        )}
        <div className="mt-3 flex flex-col gap-3 sm:flex-row sm:items-center sm:justify-between">
          <PostCardAuthor className="[&_p:last-child]:text-white/60" />
          <PostCardAction className="w-full sm:w-auto" variant="secondary">
            Read article
          </PostCardAction>
        </div>
      </div>
    </div>
  );
};

const HorizontalPostCard = () => (
  <div className="flex flex-col gap-4 rounded-lg border bg-card p-3 sm:flex-row">
    <PostCardImage className="aspect-video shrink-0 rounded-md sm:aspect-square sm:size-24" />
    <div className="flex flex-1 flex-col justify-between">
      <PostCardText />
      <div className="mt-2 flex items-center justify-between">
        <PostCardAuthor />
        <PostCardAction />
      </div>
    </div>
  </div>
);

const CompactPostCard = () => (
  <div className="rounded-lg border bg-card p-3">
    <PostCardText />
    <div className="mt-3 flex items-center justify-between">
      <PostCardAuthor />
      <PostCardAction />
    </div>
  </div>
);

const DefaultPostCard = () => (
  <div className="overflow-hidden rounded-lg border bg-card">
    <PostCardImage className="aspect-video w-full" />
    <div className="p-4">
      <PostCardText />
      <div className="mt-4 flex items-center justify-between">
        <PostCardAuthor />
        <PostCardAction />
      </div>
    </div>
  </div>
);

export const PostCardContent = () => {
  const { variant } = usePostCard();
  if (variant === "covered") {
    return <CoveredPostCard />;
  }
  if (variant === "horizontal") {
    return <HorizontalPostCard />;
  }
  if (variant === "compact") {
    return <CompactPostCard />;
  }
  return <DefaultPostCard />;
};

const PostCardRoot = ({
  actions,
  appearance,
  children,
  className,
  data,
  ...props
}: PostCardProps & { children: React.ReactNode }) => {
  const context: PostCardContextValue = {
    onReadMore: actions?.onReadMore,
    post: data?.post ?? DEFAULT_POST,
    showAuthor: appearance?.showAuthor ?? true,
    showCategory: appearance?.showCategory ?? true,
    showImage: appearance?.showImage ?? true,
    variant: appearance?.variant ?? "default",
  };
  return (
    <PostCardContext.Provider value={context}>
      <article className={className} {...props}>
        {children}
      </article>
    </PostCardContext.Provider>
  );
};

export const PostCard = PostCardRoot;

"use client";

import { Calendar, Clock, ExternalLink, Maximize2 } from "lucide-react";
import { createContext, createElement, useContext } from "react";
import type { ComponentProps, ImgHTMLAttributes } from "react";

import { Button } from "@/components/ui/button";
import { cn } from "@/lib/utils";

import type { Post } from "./types";

const BlockImage = (props: ImgHTMLAttributes<HTMLImageElement>) =>
  createElement("img", props);

interface PostDetailContextValue {
  content?: string;
  displayMode: "fullscreen" | "inline" | "pip";
  onBack?: () => void;
  onReadMore?: () => void;
  onReadRelated?: (post: Post) => void;
  post: Post;
  relatedPosts: Post[];
  showAuthor: boolean;
  showCover: boolean;
}

const PostDetailContext = createContext<PostDetailContextValue | null>(null);

export const usePostDetail = () => {
  const context = useContext(PostDetailContext);
  if (!context) {
    throw new Error("PostDetail components must be used within PostDetail");
  }
  return context;
};

const DEFAULT_POST: Post = {
  author: {
    avatar: "https://picsum.photos/seed/sarah/150/150",
    name: "Sarah Chen",
  },
  category: "Tutorial",
  coverImage: "https://picsum.photos/seed/post-detail/800/450",
  excerpt:
    "Learn how to build conversational interfaces for AI-powered applications.",
  publishedAt: "2024-01-15",
  readTime: "5 min read",
  tags: ["Tutorial", "Components", "AI", "React", "TypeScript"],
  title: "Getting Started with Agentic UI Components",
};

const DEFAULT_CONTENT = `
  <p>Building modern AI-powered applications requires a new approach to UI design. Traditional web components don't always translate well to conversational interfaces, where context and flow are paramount.</p>
  <p>Our Agentic UI component library provides purpose-built components that work seamlessly within chat interfaces.</p>
  <h2>Key Features</h2>
  <p>Each component supports inline, fullscreen, and picture-in-picture display modes while adapting to mobile devices and themes.</p>
`;

const DEFAULT_RELATED: Post[] = [
  {
    excerpt: "Best practices for intuitive UI components in chat environments.",
    readTime: "8 min read",
    title: "Designing for Conversational Interfaces",
    url: "https://example.com/posts/designing-conversational-interfaces",
  },
  {
    excerpt: "Use Model Context Protocol for seamless backend communication.",
    readTime: "12 min read",
    title: "MCP Integration Patterns",
    url: "https://example.com/posts/mcp-integration-patterns",
  },
];

const formatDate = (date: string) =>
  new Date(date).toLocaleDateString("en-US", {
    day: "numeric",
    month: "long",
    year: "numeric",
  });

export interface PostDetailProps extends ComponentProps<"article"> {
  actions?: {
    onBack?: () => void;
    onReadMore?: () => void;
    onReadRelated?: (post: Post) => void;
  };
  appearance?: {
    displayMode?: "inline" | "pip" | "fullscreen";
    showAuthor?: boolean;
    showCover?: boolean;
  };
  data?: {
    content?: string;
    post?: Post;
    relatedPosts?: Post[];
  };
}

export const PostDetailCover = ({
  className,
  ...props
}: ComponentProps<"div">) => {
  const { post, showCover } = usePostDetail();
  if (!showCover) {
    return null;
  }
  return (
    <div className={cn("overflow-hidden bg-muted", className)} {...props}>
      {post.coverImage ? (
        <BlockImage
          alt={post.title ?? "Post cover"}
          className="size-full object-cover"
          src={post.coverImage}
        />
      ) : (
        <div className="size-full bg-muted" />
      )}
    </div>
  );
};

export const PostDetailAuthor = ({
  children,
  className,
  ...props
}: ComponentProps<"div">) => {
  const { post, showAuthor } = usePostDetail();
  if (!showAuthor) {
    return null;
  }
  return (
    <div className={cn("flex items-center gap-3", className)} {...props}>
      {children ?? (
        <>
          {post.author?.avatar && (
            <BlockImage
              alt={post.author.name ?? "Author"}
              className="size-9 rounded-full object-cover"
              src={post.author.avatar}
            />
          )}
          <div>
            {post.author?.name && (
              <p className="font-medium text-sm">{post.author.name}</p>
            )}
            <div className="flex flex-wrap items-center gap-3 text-muted-foreground text-xs">
              {post.publishedAt && (
                <span className="flex items-center gap-1">
                  <Calendar className="size-3.5" />
                  {formatDate(post.publishedAt)}
                </span>
              )}
              {post.readTime && (
                <span className="flex items-center gap-1">
                  <Clock className="size-3.5" />
                  {post.readTime}
                </span>
              )}
            </div>
          </div>
        </>
      )}
    </div>
  );
};

export const PostDetailHeader = ({
  children,
  className,
  ...props
}: ComponentProps<"header">) => {
  const { post } = usePostDetail();
  return (
    <header className={className} {...props}>
      {children ?? (
        <>
          {post.category && (
            <p className="font-medium text-muted-foreground text-xs uppercase tracking-wide">
              {post.category}
            </p>
          )}
          {post.title && (
            <h1 className="mt-2 font-bold text-2xl leading-tight sm:text-4xl">
              {post.title}
            </h1>
          )}
          {post.excerpt && (
            <p className="mt-3 text-muted-foreground sm:text-lg">
              {post.excerpt}
            </p>
          )}
          <PostDetailAuthor className="mt-5" />
        </>
      )}
    </header>
  );
};

export const PostDetailBody = ({
  children,
  className,
  ...props
}: ComponentProps<"div">) => {
  const { content } = usePostDetail();
  if (children) {
    return (
      <div className={className} {...props}>
        {children}
      </div>
    );
  }
  if (!content) {
    return null;
  }
  return (
    <div
      className={cn(
        "prose prose-neutral max-w-none dark:prose-invert prose-headings:font-semibold prose-p:text-muted-foreground",
        className
      )}
      dangerouslySetInnerHTML={{ __html: content }}
      {...props}
    />
  );
};

export const PostDetailRelated = ({
  children,
  className,
  ...props
}: ComponentProps<"div">) => {
  const { onReadRelated, relatedPosts } = usePostDetail();
  if (!(children || relatedPosts.length > 0)) {
    return null;
  }
  return (
    <div className={cn("border-t pt-6", className)} {...props}>
      {children ?? (
        <>
          <h2 className="mb-4 font-semibold text-lg">Related posts</h2>
          <div className="space-y-2">
            {relatedPosts.map((post, index) => (
              <button
                className="flex w-full items-center gap-3 rounded-lg border p-3 text-left transition-colors hover:bg-muted"
                key={`${post.title ?? "post"}-${index}`}
                onClick={() => onReadRelated?.(post)}
                type="button"
              >
                <div className="min-w-0 flex-1">
                  {post.title && <p className="font-medium">{post.title}</p>}
                  {post.excerpt && (
                    <p className="mt-1 line-clamp-1 text-muted-foreground text-sm">
                      {post.excerpt}
                    </p>
                  )}
                  {post.readTime && (
                    <p className="mt-1 text-muted-foreground text-xs">
                      {post.readTime}
                    </p>
                  )}
                </div>
                <ExternalLink className="size-4 shrink-0 text-muted-foreground" />
              </button>
            ))}
          </div>
        </>
      )}
    </div>
  );
};

const CompactPostDetail = () => {
  const { displayMode, onReadMore, post } = usePostDetail();
  return (
    <div className="overflow-hidden rounded-xl border bg-card">
      <PostDetailCover className="aspect-video w-full" />
      <div className="p-4">
        {post.category && (
          <p className="font-medium text-muted-foreground text-xs uppercase tracking-wide">
            {post.category}
          </p>
        )}
        {post.title && (
          <h2 className="mt-1 line-clamp-2 font-semibold text-xl">
            {post.title}
          </h2>
        )}
        {post.excerpt && (
          <p className="mt-2 line-clamp-3 text-muted-foreground text-sm">
            {post.excerpt}
          </p>
        )}
        <PostDetailAuthor className="mt-4" />
        <Button className="mt-4 w-full" onClick={onReadMore} size="sm">
          {displayMode === "pip" ? "Open article" : "Read article"}
          <Maximize2 className="ml-2 size-4" />
        </Button>
      </div>
    </div>
  );
};

const FullPostDetail = () => (
  <div className="rounded-xl border bg-card">
    <PostDetailCover className="aspect-[21/9] w-full rounded-t-xl" />
    <div className="mx-auto max-w-3xl space-y-8 px-5 py-8 sm:px-8">
      <PostDetailHeader />
      <PostDetailBody />
      <PostDetailRelated />
    </div>
  </div>
);

export const PostDetailContent = () => {
  const { displayMode } = usePostDetail();
  return displayMode === "fullscreen" ? (
    <FullPostDetail />
  ) : (
    <CompactPostDetail />
  );
};

const PostDetailRoot = ({
  actions,
  appearance,
  children,
  className,
  data,
  ...props
}: PostDetailProps & { children: React.ReactNode }) => {
  const context: PostDetailContextValue = {
    content: data?.content ?? DEFAULT_CONTENT,
    displayMode: appearance?.displayMode ?? "inline",
    onBack: actions?.onBack,
    onReadMore: actions?.onReadMore,
    onReadRelated: actions?.onReadRelated,
    post: data?.post ?? DEFAULT_POST,
    relatedPosts: data?.relatedPosts ?? DEFAULT_RELATED,
    showAuthor: appearance?.showAuthor ?? true,
    showCover: appearance?.showCover ?? true,
  };
  return (
    <PostDetailContext.Provider value={context}>
      <article className={className} {...props}>
        {children}
      </article>
    </PostDetailContext.Provider>
  );
};

export const PostDetail = PostDetailRoot;
